module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const align = String(args.align || 'center').toLowerCase();
const alignItems = align === 'left' ? 'flex-start' : align === 'right' ? 'flex-end' : 'center';
const numbered = String(args.numbered) === 'true';
const radius = String(args.shape || 'rounded').toLowerCase() === 'square' ? '0px' : '8px';
const nodeW = Math.max(20, Math.min(100, parseFloat(args.maxwidth) || 80));
const nodes = sections.map((s) => (s || '').trim()).filter(Boolean);
let html = `\n\n<div class="mdp-mod-flow${numbered ? ' mdp-fl-numbered' : ''}" style="--fl-color:${color}; --fl-radius:${radius}; --fl-nodew:${nodeW}%; align-items:${alignItems};">`;
nodes.forEach((raw, i) => {
  let text = raw, edge = '';
  const em = raw.match(/^\[([^\]]+)\]\s*([\s\S]*)$/);
  if (em) { edge = em[1].trim(); text = em[2].trim(); }
  if (i > 0) html += `<div class="mdp-fl-arrow">${edge ? `<span class="mdp-fl-edge">${esc(edge)}</span>` : ''}↓</div>`;
  const decision = /\?\s*$/.test(text);
  html += `<div class="mdp-fl-node ${decision ? 'mdp-fl-decision' : 'mdp-fl-step'}"><div class="mdp-fl-inner">\n\n${text}\n\n</div></div>`;
});
html += `</div>\n\n`;
return html;
